import { useEffect } from 'react';

import { useInteractiveTooltip } from './useInteractiveTooltip.js';
import { TOOLTIP_MAX_HEIGHT } from '../components/InteractiveChartTooltip.styles.js';

export const useHandleSetScrollbar = (totalSize: number) => {
  const hasScrollbar = totalSize > TOOLTIP_MAX_HEIGHT;

  const { setHasScrollbar } = useInteractiveTooltip();

  useEffect(() => {
    setHasScrollbar(hasScrollbar);
  }, [setHasScrollbar, hasScrollbar]);
};
